sql:
SELECT SUM(total_cost) AS total_rent_cost
FROM fixed_costs
WHERE cost_type = 'Rent' AND payment_frequency = 'monthly';

SELECT total_cost
FROM fixed_costs
WHERE cost_type = 'Rent';

SELECT machinery_type, total_cost
FROM machinery_costs
WHERE cost_id = 1;

SELECT SUM(total_cost) AS grand_total_material_cost
FROM material_costs
WHERE supplier_id = 0;

