SELECT total_land_area
FROM farms
ORDER BY total_land_area DESC;

SELECT total_cost
FROM material_costs
WHERE total_cost > 1000;

SELECT SUM(total_cost) AS total_fertilizer_cost
FROM material_costs
WHERE material_type = 'Fertilizers';
